//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String title;
    Author author;
    Repository repository;
    String license;
    String description;
    List<String> keywords;
    List<String> categories;
    String main;
    String homepage;
    List<String> contributors;
    List<String> files;
    String npmName;
    List<NpmFileMap> npmFileMap;

    Package({
        required this.name,
        required this.version,
        required this.title,
        required this.author,
        required this.repository,
        required this.license,
        required this.description,
        required this.keywords,
        required this.categories,
        required this.main,
        required this.homepage,
        required this.contributors,
        required this.files,
        required this.npmName,
        required this.npmFileMap,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        title: json["title"],
        author: Author.fromJson(json["author"]),
        repository: Repository.fromJson(json["repository"]),
        license: json["license"],
        description: json["description"],
        keywords: List<String>.from(json["keywords"].map((x) => x)),
        categories: List<String>.from(json["categories"].map((x) => x)),
        main: json["main"],
        homepage: json["homepage"],
        contributors: List<String>.from(json["contributors"].map((x) => x)),
        files: List<String>.from(json["files"].map((x) => x)),
        npmName: json["npmName"],
        npmFileMap: List<NpmFileMap>.from(json["npmFileMap"].map((x) => NpmFileMap.fromJson(x))),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "title": title,
        "author": author.toJson(),
        "repository": repository.toJson(),
        "license": license,
        "description": description,
        "keywords": List<dynamic>.from(keywords.map((x) => x)),
        "categories": List<dynamic>.from(categories.map((x) => x)),
        "main": main,
        "homepage": homepage,
        "contributors": List<dynamic>.from(contributors.map((x) => x)),
        "files": List<dynamic>.from(files.map((x) => x)),
        "npmName": npmName,
        "npmFileMap": List<dynamic>.from(npmFileMap.map((x) => x.toJson())),
    };
}

class Author {
    String name;
    String url;

    Author({
        required this.name,
        required this.url,
    });

    factory Author.fromJson(Map<String, dynamic> json) => Author(
        name: json["name"],
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "url": url,
    };
}

class NpmFileMap {
    String basePath;
    List<String> files;

    NpmFileMap({
        required this.basePath,
        required this.files,
    });

    factory NpmFileMap.fromJson(Map<String, dynamic> json) => NpmFileMap(
        basePath: json["basePath"],
        files: List<String>.from(json["files"].map((x) => x)),
    );

    Map<String, dynamic> toJson() => {
        "basePath": basePath,
        "files": List<dynamic>.from(files.map((x) => x)),
    };
}

class Repository {
    String type;
    String url;

    Repository({
        required this.type,
        required this.url,
    });

    factory Repository.fromJson(Map<String, dynamic> json) => Repository(
        type: json["type"],
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "type": type,
        "url": url,
    };
}
